484	/* Load each parser definition set in 'struct flb_cf *cf' */
485	int flb_parser_load_parser_definitions(const char *cfg, struct flb_cf *cf,
486	                                       struct flb_config *config)
487	{
488	    int i = 0;
489	    flb_sds_t name;
490	    flb_sds_t format;
491	    flb_sds_t regex;
492	    flb_sds_t time_fmt;
493	    flb_sds_t time_key;
494	    flb_sds_t time_offset;
495	    flb_sds_t types_str;
496	    flb_sds_t tmp_str;
497	    int skip_empty;
498	    int time_keep;
499	    int time_strict;
500	    int time_system_timezone;
501	    int logfmt_no_bare_keys;
502	    int types_len;
503	    struct mk_list *head;
504	    struct mk_list *decoders = NULL;
505	    struct flb_cf_section *s;
506	    struct flb_parser_types *types = NULL;
507	
508	    /* Read all 'parser' sections */
509	    mk_list_foreach(head, &cf->parsers) {
510	        name = NULL;
511	        format = NULL;
512	        regex = NULL;
513	        time_fmt = NULL;
514	        time_key = NULL;
515	        time_offset = NULL;
516	        types_str = NULL;
517	        tmp_str = NULL;
518	
519	        /* retrieve the section context */
520	        s = mk_list_entry(head, struct flb_cf_section, _head_section);
521	
522	        /* name */
523	        name = get_parser_key(config, cf, s, "name");
524	        if (!name) {
525	            flb_error("[parser] no parser 'name' found in file '%s'", cfg);
526	            goto fconf_early_error;
527	        }
528	
529	        /* format */
530	        format = get_parser_key(config, cf, s, "format");
531	        if (!format) {
532	            flb_error("[parser] no parser 'format' found for '%s' in file '%s'",
533	                      name, cfg);
534	            goto fconf_early_error;
535	        }
536	
537	        /* regex (if 'format' == 'regex') */
538	        regex = get_parser_key(config, cf, s, "regex");
539	        if (!regex && strcmp(format, "regex") == 0) {
540	            flb_error("[parser] no parser 'regex' found for '%s' in file '%s",
541	                      name, cfg);
542	            goto fconf_early_error;
543	        }
544	
545	        /* skip_empty_values */
546	        skip_empty = FLB_TRUE;
547	        tmp_str = get_parser_key(config, cf, s, "skip_empty_values");
548	        if (tmp_str) {
549	            skip_empty = flb_utils_bool(tmp_str);
550	            flb_sds_destroy(tmp_str);
551	        }
552	
553	        /* time_format */
554	        time_fmt = get_parser_key(config, cf, s, "time_format");
555	
556	        /* time_key */
557	        time_key = get_parser_key(config, cf, s, "time_key");
558	
559	        /* time_keep */
560	        time_keep = FLB_FALSE;
561	        tmp_str = get_parser_key(config, cf, s, "time_keep");
562	        if (tmp_str) {
563	            time_keep = flb_utils_bool(tmp_str);
564	            flb_sds_destroy(tmp_str);
565	        }
566	
567	        /* time_strict */
568	        time_strict = FLB_TRUE;
569	        tmp_str = get_parser_key(config, cf, s, "time_strict");
570	        if (tmp_str) {
571	            time_strict = flb_utils_bool(tmp_str);
572	            flb_sds_destroy(tmp_str);
573	        }
574	
575	        time_system_timezone = FLB_FALSE;
576	        tmp_str = get_parser_key(config, cf, s, "time_system_timezone");
577	        if (tmp_str) {
578	            time_system_timezone = flb_utils_bool(tmp_str);
579	            flb_sds_destroy(tmp_str);
580	        }
581	
582	        /* time_offset (UTC offset) */
583	        time_offset = get_parser_key(config, cf, s, "time_offset");
584	
585	        /* logfmt_no_bare_keys */
586	        logfmt_no_bare_keys = FLB_FALSE;
587	        tmp_str = get_parser_key(config, cf, s, "logfmt_no_bare_keys");
588	        if (tmp_str) {
589	            logfmt_no_bare_keys = flb_utils_bool(tmp_str);
590	            flb_sds_destroy(tmp_str);
591	        }
592	
593	        /* types */
594	        types_str = get_parser_key(config, cf, s, "types");
595	        if (types_str) {
596	            types_len = proc_types_str(types_str, &types);
597	        }
598	        else {
599	            types_len = 0;
600	        }
601	
602	        /* Decoders */
603	        decoders = flb_parser_decoder_list_create(s);
604	
605	        /* Create the parser context */
606	        if (!flb_parser_create(name, format, regex, skip_empty,
607	                               time_fmt, time_key, time_offset, time_keep, time_strict,
608	                               time_system_timezone, logfmt_no_bare_keys, types, types_len,
609	                               decoders, config)) {
610	            goto fconf_error;
611	        }
612	
613	        flb_debug("[parser] new parser registered: %s", name);
614	
615	        flb_sds_destroy(name);
616	        flb_sds_destroy(format);
617	
618	        if (regex) {
619	            flb_sds_destroy(regex);
620	        }
621	        if (time_fmt) {
622	            flb_sds_destroy(time_fmt);
623	        }
624	        if (time_key) {
625	            flb_sds_destroy(time_key);
626	        }
627	        if (time_offset) {
628	            flb_sds_destroy(time_offset);
629	        }
630	        if (types_str) {
631	            flb_sds_destroy(types_str);
632	        }
633	        decoders = NULL;
634	    }
635	
636	    return 0;
637	
638	 /* Use early exit before call to flb_parser_create */
639	 fconf_early_error:
640	    if (name) {
641	        flb_sds_destroy(name);
642	    }
643	    if (format) {
644	        flb_sds_destroy(format);
645	    }
646	    if (regex) {
647	        flb_sds_destroy(regex);
648	    }
649	    return -1;
650	
651	 fconf_error:
652	    flb_sds_destroy(name);
653	    flb_sds_destroy(format);
654	    if (regex) {
655	        flb_sds_destroy(regex);
656	    }
657	    if (time_fmt) {
658	        flb_sds_destroy(time_fmt);
659	    }
660	    if (time_key) {
661	        flb_sds_destroy(time_key);
662	    }
663	    if (time_offset) {
664	        flb_sds_destroy(time_offset);
665	    }
666	    if (types_str) {
667	        flb_sds_destroy(types_str);
668	    }
669	    if (types_len) {
670	        for (i=0; i<types_len; i++){
671	            if (types[i].key != NULL) {
672	                flb_free(types[i].key);
673	            }
674	        }
675	        flb_free(types);
676	    }
677	    if (decoders) {
678	        flb_parser_decoder_list_destroy(decoders);
679	    }
680	    return -1;
681	}
