694	static int multiline_load_regex_rules(struct flb_ml_parser *ml_parser,
695	                                      struct flb_cf_section *section,
696	                                      struct flb_config *config)
697	{
698	    int ret;
699	    char *to_state = NULL;
700	    struct mk_list list;
701	    struct cfl_list *head;
702	    struct cfl_kvpair *entry;
703	    struct flb_slist_entry *from_state;
704	    struct flb_slist_entry *regex_pattern;
705	    struct flb_slist_entry *tmp;
706	    struct mk_list *g_head;
707	    struct flb_cf_group *group;
708	    struct cfl_variant *var_state;
709	    struct cfl_variant *var_regex;
710	    struct cfl_variant *var_next_state;
711	
712	    /* Check if we have groups (coming from Yaml style config */
713	    mk_list_foreach(g_head, &section->groups) {
714	        /* Every group is a rule */
715	        group = cfl_list_entry(g_head, struct flb_cf_group, _head);
716	
717	        var_state = cfl_kvlist_fetch(group->properties, "state");
718	        if (!var_state || var_state->type != CFL_VARIANT_STRING) {
719	            flb_error("[multiline parser: %s] invalid 'state' key", ml_parser->name);
720	            return -1;
721	        }
722	
723	        var_regex = cfl_kvlist_fetch(group->properties, "regex");
724	        if (!var_regex || var_regex->type != CFL_VARIANT_STRING) {
725	            flb_error("[multiline parser: %s] invalid 'regex' key", ml_parser->name);
726	            return -1;
727	        }
728	
729	        var_next_state = cfl_kvlist_fetch(group->properties, "next_state");
730	        if (!var_next_state || var_next_state->type != CFL_VARIANT_STRING) {
731	            flb_error("[multiline parser: %s] invalid 'next_state' key", ml_parser->name);
732	            return -1;
733	        }
734	
735	        ret = multiline_rule_create(ml_parser,
736	                                    var_state->data.as_string,
737	                                    var_regex->data.as_string,
738	                                    var_next_state->data.as_string);
739	
740	        if (ret == -1) {
741	            flb_error("[multiline parser: %s] error creating rule", ml_parser->name);
742	            return -1;
743	        }
744	    }
745	
746	    /* Multiline rules set by a Fluent Bit classic mode config */
747	    cfl_list_foreach(head, &section->properties->list) {
748	        entry = cfl_list_entry(head, struct cfl_kvpair, _head);
749	
750	        /* only process 'rule' keys */
751	        if (strcasecmp(entry->key, "rule") != 0) {
752	            continue;
753	        }
754	
755	        mk_list_init(&list);
756	        ret = flb_slist_split_tokens(&list, entry->val->data.as_string, 3);
757	        if (ret == -1) {
758	            flb_error("[multiline parser: %s] invalid section on key '%s'",
759	                    ml_parser->name, entry->key);
760	            return -1;
761	        }
762	
763	        /* Get entries from the line */
764	        from_state    = flb_slist_entry_get(&list, 0);
765	        regex_pattern = flb_slist_entry_get(&list, 1);
766	        tmp = flb_slist_entry_get(&list, 2);
767	        if (tmp) {
768	            to_state  = tmp->str;
769	        }
770	        else {
771	            to_state = NULL;
772	        }
773	
774	        if (!from_state) {
775	            flb_error("[multiline parser: %s] 'from_state' is mandatory",
776	                      ml_parser->name);
777	            flb_slist_destroy(&list);
778	            return -1;
779	        }
780	
781	        if (!regex_pattern) {
782	            flb_error("[multiline parser: %s] 'regex_pattern' is mandatory",
783	                      ml_parser->name);
784	            flb_slist_destroy(&list);
785	            return -1;
786	        }
787	
788	        ret = multiline_rule_create(ml_parser,
789	                                    from_state->str,
790	                                    regex_pattern->str,
791	                                    to_state);
792	        if (ret == -1) {
793	            flb_error("[multiline parser: %s] error creating rule",
794	                      ml_parser->name);
795	            flb_slist_destroy(&list);
796	            return -1;
797	        }
798	
799	        flb_slist_destroy(&list);
800	    }
801	
802	    /* Map the rules (mandatory for regex rules) */
803	    ret = flb_ml_parser_init(ml_parser);
804	    if (ret != 0) {
805	        flb_error("[multiline parser: %s] invalid mapping rules, check the states",
806	                  ml_parser->name);
807	        return -1;
808	    }
809	
810	    return 0;
811	}
