814	/* config file: read 'multiline_parser' sections */
815	int flb_parser_load_multiline_parser_definitions(const char *cfg, struct flb_cf *cf,
816	                                                 struct flb_config *config)
817	{
818	    int ret;
819	    int type;
820	    flb_sds_t name;
821	    flb_sds_t match_string;
822	    int negate;
823	    flb_sds_t key_content;
824	    flb_sds_t key_pattern;
825	    flb_sds_t key_group;
826	    flb_sds_t parser;
827	    flb_sds_t tmp;
828	    int flush_timeout;
829	    struct flb_parser *parser_ctx = NULL;
830	    struct mk_list *head;
831	    struct flb_cf_section *s;
832	    struct flb_ml_parser *ml_parser;
833	
834	    /*
835	     * debug content of cf: flb_cf_dump(cf);
836	     */
837	
838	    /* read all 'multiline_parser' sections */
839	    mk_list_foreach(head, &cf->multiline_parsers) {
840	        ml_parser = NULL;
841	        name = NULL;
842	        type = -1;
843	        match_string = NULL;
844	        negate = FLB_FALSE;
845	        key_content = NULL;
846	        key_pattern = NULL;
847	        key_group = NULL;
848	        parser = NULL;
849	        flush_timeout = -1;
850	        tmp = NULL;
851	
852	        s = mk_list_entry(head, struct flb_cf_section, _head_section);
853	
854	        /* name */
855	        name = get_parser_key(config, cf, s, "name");
856	        if (!name) {
857	            flb_error("[multiline_parser] no 'name' defined in file '%s'", cfg);
858	            goto fconf_error;
859	        }
860	
861	        /* type */
862	        tmp = get_parser_key(config, cf, s, "type");
863	        if (!tmp) {
864	            flb_error("[multiline_parser] no 'type' defined in file '%s'", cfg);
865	            goto fconf_error;
866	        }
867	        else {
868	            type = flb_ml_type_lookup(tmp);
869	            if (type == -1) {
870	                flb_error("[multiline_parser] invalid type '%s'", tmp);
871	                goto fconf_error;
872	            }
873	            flb_sds_destroy(tmp);
874	        }
875	
876	        /* match_string */
877	        match_string = get_parser_key(config, cf, s, "match_string");
878	
879	        /* negate */
880	        tmp = get_parser_key(config, cf, s, "negate");
881	        if (tmp) {
882	            negate = flb_utils_bool(tmp);
883	            flb_sds_destroy(tmp);
884	        }
885	
886	        /* key_content */
887	        key_content = get_parser_key(config, cf, s, "key_content");
888	
889	        /* key_pattern */
890	        key_pattern = get_parser_key(config, cf, s, "key_pattern");
891	
892	        /* key_group */
893	        key_group = get_parser_key(config, cf, s, "key_group");
894	
895	        /* parser */
896	        parser = get_parser_key(config, cf, s, "parser");
897	
898	        /* flush_timeout */
899	        tmp = get_parser_key(config, cf, s, "flush_timeout");
900	        if (tmp) {
901	            flush_timeout = atoi(tmp);
902	        }
903	
904	        if (parser) {
905	            parser_ctx = flb_parser_get(parser, config);
906	        }
907	        ml_parser = flb_ml_parser_create(config, name, type, match_string,
908	                                         negate, flush_timeout, key_content,
909	                                         key_group, key_pattern,
910	                                         parser_ctx, parser);
911	        if (!ml_parser) {
912	            goto fconf_error;
913	        }
914	
915	        /* if type is regex, process rules */
916	        if (type == FLB_ML_REGEX) {
917	            ret = multiline_load_regex_rules(ml_parser, s, config);
918	            if (ret != 0) {
919	                goto fconf_error;
920	            }
921	        }
922	
923	        flb_sds_destroy(name);
924	        flb_sds_destroy(match_string);
925	        flb_sds_destroy(key_content);
926	        flb_sds_destroy(key_pattern);
927	        flb_sds_destroy(key_group);
928	        flb_sds_destroy(parser);
929	        flb_sds_destroy(tmp);
930	    }
931	
932	    return 0;
933	
934	 fconf_error:
935	    if (ml_parser) {
936	        flb_ml_parser_destroy(ml_parser);
937	    }
938	    flb_sds_destroy(name);
939	    flb_sds_destroy(match_string);
940	    flb_sds_destroy(key_content);
941	    flb_sds_destroy(key_pattern);
942	    flb_sds_destroy(key_group);
943	    flb_sds_destroy(parser);
944	    flb_sds_destroy(tmp);
945	
946	    return -1;
947	}
