1128	/*
1129	 * Parse the '%L' (subseconds) part into `subsec`.
1130	 *
1131	 *   2020-10-23 12:00:31.415213 JST
1132	 *                       ----------
1133	 *
1134	 * Return the number of characters consumed, or -1 on error.
1135	 */
1136	static int parse_subseconds(char *str, int len, double *subsec)
1137	{
1138	    char buf[16];
1139	    char *end;
1140	    int consumed;
1141	    int digits = 9;  /* 1 ns = 000000001 (9 digits) */
1142	
1143	    if (len < digits) {
1144	        digits = len;
1145	    }
1146	    memcpy(buf, "0.", 2);
1147	    memcpy(buf + 2, str, digits);
1148	    buf[digits + 2] = '\0';
1149	
1150	    *subsec = strtod(buf, &end);
1151	
1152	    consumed = end - buf - 2;
1153	    if (consumed <= 0) {
1154	        return -1;
1155	    }
1156	    return consumed;
1157	}
1158	
1159	int flb_parser_time_lookup(const char *time_str, size_t tsize,
1160	                           time_t now,
1161	                           struct flb_parser *parser,
1162	                           struct flb_tm *tm, double *ns)
1163	{
1164	    int ret;
1165	    time_t time_now;
1166	    char *p = NULL;
1167	    char *fmt;
1168	    int time_len = tsize;
1169	    const char *time_ptr = time_str;
1170	    char tmp[64];
1171	    struct tm tmy;
1172	
1173	    *ns = 0;
1174	
1175	    if (tsize > sizeof(tmp) - 1) {
1176	        flb_error("[parser] time string length is too long");
1177	        return -1;
1178	    }
1179	
1180	    /*
1181	     * Some records coming from old Syslog messages do not contain the
1182	     * year, so it's required to ingest this information in the value
1183	     * to be parsed.
1184	     */
1185	    if (parser->time_with_year == FLB_FALSE) {
1186	        /* Given time string is too long */
1187	        if (time_len + 6 >= sizeof(tmp)) {
1188	            return -1;
1189	        }
1190	
1191	        /*
1192	         * This is not the most elegant way but for now it let
1193	         * get the work done.
1194	         */
1195	        if (now <= 0) {
1196	            time_now = time(NULL);
1197	        }
1198	        else {
1199	            time_now = now;
1200	        }
1201	
1202	        gmtime_r(&time_now, &tmy);
1203	
1204	        /* Make the timestamp default to today */
1205	        tm->tm.tm_mon = tmy.tm_mon;
1206	        tm->tm.tm_mday = tmy.tm_mday;
1207	
1208	        uint64_t t = tmy.tm_year + 1900;
1209	
1210	        fmt = tmp;
1211	        u64_to_str(t, fmt);
1212	        fmt += 4;
1213	        *fmt++ = ' ';
1214	
1215	        memcpy(fmt, time_ptr, time_len);
1216	        fmt += time_len;
1217	        *fmt++ = '\0';
1218	
1219	        time_ptr = tmp;
1220	        time_len = strlen(tmp);
1221	        p = flb_strptime(time_ptr, parser->time_fmt_year, tm);
1222	    }
1223	    else {
1224	        /*
1225	         * We must ensure string passed to flb_strptime is
1226	         * null-terminated, which time_ptr is not guaranteed
1227	         * to be. So we use tmp to hold our string.
1228	         */
1229	        if (time_len >= sizeof(tmp)) {
1230	            return -1;
1231	        }
1232	        memcpy(tmp, time_ptr, time_len);
1233	        tmp[time_len] = '\0';
1234	        time_ptr = tmp;
1235	        time_len = strlen(tmp);
1236	
1237	        p = flb_strptime(time_ptr, parser->time_fmt, tm);
1238	    }
1239	
1240	    if (p == NULL) {
1241	        if (parser->time_strict) {
1242	            flb_error("[parser] cannot parse '%.*s'", (int)tsize, time_str);
1243	            return -1;
1244	        }
1245	        flb_debug("[parser] non-exact match '%.*s'", (int)tsize, time_str);
1246	        return 0;
1247	    }
1248	
1249	    if (parser->time_frac_secs) {
1250	        ret = parse_subseconds(p, time_len - (p - time_ptr), ns);
1251	        if (ret < 0) {
1252	            if (parser->time_strict) {
1253	                flb_error("[parser] cannot parse %%L for '%.*s'", (int)tsize, time_str);
1254	                return -1;
1255	            }
1256	            flb_debug("[parser] non-exact match on %%L '%.*s'", (int)tsize, time_str);
1257	            return 0;
1258	        }
1259	        p += ret;
1260	
1261	        /* Parse the remaining part after %L */
1262	        p = flb_strptime(p, parser->time_frac_secs, tm);
1263	        if (p == NULL) {
1264	            if (parser->time_strict) {
1265	                flb_error("[parser] cannot parse '%.*s' after %%L", (int)tsize, time_str);
1266	                return -1;
1267	            }
1268	            flb_debug("[parser] non-exact match after %%L '%.*s'", (int)tsize, time_str);
1269	            return 0;
1270	        }
1271	    }
1272	
1273	    if (parser->time_with_tz == FLB_FALSE) {
1274	        flb_tm_gmtoff(tm) = parser->time_offset;
1275	    }
1276	
1277	    return 0;
1278	}
1279	
1280	int flb_parser_typecast(const char *key, int key_len,
1281	                        const char *val, int val_len,
1282	                        msgpack_packer *pck,
1283	                        struct flb_parser_types *types,
1284	                        int types_len)
1285	{
1286	    int i;
1287	    int error = FLB_FALSE;
1288	    char *tmp_str;
1289	    int casted = FLB_FALSE;
1290	
1291	    for(i=0; i<types_len; i++){
1292	        if (types[i].key != NULL
1293	            && key_len == types[i].key_len &&
1294	            !strncmp(key, types[i].key, key_len)) {
1295	
1296	            casted = FLB_TRUE;
1297	
1298	            msgpack_pack_str(pck, key_len);
1299	            msgpack_pack_str_body(pck, key, key_len);
1300	
1301	            switch (types[i].type) {
1302	            case FLB_PARSER_TYPE_INT:
1303	                {
1304	                    long long lval;
1305	
1306	                    /* msgpack char is not null terminated.
1307	                       So make a temporary copy.
1308	                     */
1309	                    tmp_str = flb_strndup(val, val_len);
1310	                    lval = atoll(tmp_str);
1311	                    flb_free(tmp_str);
1312	                    msgpack_pack_int64(pck, lval);
1313	                }
1314	                break;
1315	            case FLB_PARSER_TYPE_HEX:
1316	                {
1317	                    unsigned long long lval;
1318	                    tmp_str = flb_strndup(val, val_len);
1319	                    lval = strtoull(tmp_str, NULL, 16);
1320	                    flb_free(tmp_str);
1321	                    msgpack_pack_uint64(pck, lval);
1322	                }
1323	                break;
1324	
1325	            case FLB_PARSER_TYPE_FLOAT:
1326	                {
1327	                    double dval;
1328	                    tmp_str = flb_strndup(val, val_len);
1329	                    dval = atof(tmp_str);
1330	                    flb_free(tmp_str);
1331	                    msgpack_pack_double(pck, dval);
1332	                }
1333	                break;
1334	            case FLB_PARSER_TYPE_BOOL:
1335	                if (val_len >= 4 && !strncasecmp(val, "true", 4)) {
1336	                    msgpack_pack_true(pck);
1337	                }
1338	                else if(val_len >= 5 && !strncasecmp(val, "false", 5)){
1339	                    msgpack_pack_false(pck);
1340	                }
1341	                else {
1342	                    error = FLB_TRUE;
1343	                }
1344	                break;
1345	            case FLB_PARSER_TYPE_STRING:
1346	                msgpack_pack_str(pck, val_len);
1347	                msgpack_pack_str_body(pck, val, val_len);
1348	                break;
1349	            default:
1350	                error = FLB_TRUE;
1351	            }
1352	            if (error == FLB_TRUE) {
1353	                /* We need to null-terminate key for flb_warn, as it expects
1354	                 * a null-terminated string, which key is not guaranteed
1355	                 * to be */
1356	                char *nt_key = flb_malloc(key_len + 1);
1357	                if (nt_key != NULL) {
1358	                    memcpy(nt_key, key, key_len);
1359	                    nt_key[key_len] = '\0';
1360	                    flb_warn("[PARSER] key=%s cast error. save as string.", nt_key);
1361	                    flb_free(nt_key);
1362	                }
1363	                msgpack_pack_str(pck, val_len);
1364	                msgpack_pack_str_body(pck, val, val_len);
1365	            }
1366	            break;
1367	        }
1368	    }
1369	
1370	    if (casted == FLB_FALSE) {
1371	        msgpack_pack_str(pck, key_len);
1372	        msgpack_pack_str_body(pck, key, key_len);
1373	        msgpack_pack_str(pck, val_len);
1374	        msgpack_pack_str_body(pck, val, val_len);
1375	    }
1376	    return 0;
1377	}
