47	void wait_with_timeout(uint32_t timeout_ms, char **out_result)
48	{
49	    struct flb_time start_time;
50	    struct flb_time end_time;
51	    struct flb_time diff_time;
52	    uint64_t elapsed_time_flb = 0;
53	    char *output = NULL;
54	
55	    flb_time_get(&start_time);
56	
57	    while (true) {
58	        output = get_output();
59	
60	        if (output != NULL) {
61	            *out_result = output;
62	            break;
63	        }
64	
65	        flb_time_msleep(100);
66	        flb_time_get(&end_time);
67	        flb_time_diff(&end_time, &start_time, &diff_time);
68	        elapsed_time_flb = flb_time_to_nanosec(&diff_time) / 1000000;
69	
70	        if (elapsed_time_flb > timeout_ms) {
71	            flb_warn("[timeout] elapsed_time: %ld", elapsed_time_flb);
72	            // Reached timeout.
73	            break;
74	        }
75	    }
76	}
