95	
96	    ctx = flb_create();
97	
98	    /* Configure service */
99	    flb_service_set(ctx, "Flush", FLUSH_INTERVAL, "Grace" "1", "Log_Level", "debug", NULL);
100	
101	    /* Input */
102	    in_ffd = flb_input(ctx, (char *) "lib", NULL);
103	    TEST_CHECK(in_ffd >= 0);
104	    flb_input_set(ctx, in_ffd,
105	                  "Tag", "test",
106	                  NULL);
107	
108	    /* Parser */
109	    parser = flb_parser_create("dummy_test", "regex", "^(?<INT>[^ ]+) (?<FLOAT>[^ ]+) (?<BOOL>[^ ]+) (?<STRING>.+)$",
110	                               FLB_TRUE,
111	                               NULL, NULL, NULL, MK_FALSE, MK_TRUE, FLB_FALSE, FLB_FALSE, NULL, 0,
112	                               NULL, ctx->config);
113	    TEST_CHECK(parser != NULL);
114	
115	    /* Filter */
116	    filter_ffd = flb_filter(ctx, (char *) "parser", NULL);
117	    TEST_CHECK(filter_ffd >= 0);
118	    ret = flb_filter_set(ctx, filter_ffd,
119	                         "Match", "test",
120	                         "Key_Name", "data",
121	                         "Parser", "dummy_test",
122	                         "Reserve_Data", "On",
123	                         "Preserve_Key", "Off",
124	                         NULL);
125	    TEST_CHECK(ret == 0);
126	
127	    /* Output */
128	    out_ffd = flb_output(ctx, (char *) "lib", &cb);
129	    TEST_CHECK(out_ffd >= 0);
130	    flb_output_set(ctx, out_ffd,
131	                   "Match", "*",
132	                   "format", "json",
133	                   NULL);
134	
135	    /* Start the engine */
136	    ret = flb_start(ctx);
137	    TEST_CHECK(ret == 0);
138	
139	    /* Ingest data */
140	    p = "[1448403340, {\"data\":\"100 0.5 true This is an example\", \"extra\":\"Some more data\"}]";
141	    bytes = flb_lib_push(ctx, in_ffd, p, strlen(p));
142	    TEST_CHECK(bytes == strlen(p));
143	
144	    wait_with_timeout(2000, &output); /* waiting flush and ensuring data flush */
145	    TEST_CHECK_(output != NULL, "Expected output to not be NULL");
146	    if (output != NULL) {
147	        /* check timestamp */
148	        expected = "[1448403340.000000,{";
149	        TEST_CHECK_(strstr(output, expected) != NULL, "Expected output to contain '%s', got '%s'", expected, output);
150	        /* check fields were extracted */
151	        expected = "\"INT\":\"100\",\"FLOAT\":\"0.5\",\"BOOL\":\"true\",\"STRING\":\"This is an example\"";
152	        TEST_CHECK_(strstr(output, expected) != NULL, "Expected output to contain '%s', got '%s'", expected, output);
153	        /* check original field was not preserved */
154	        expected = "\"data\":\"100 0.5 true This is an example\"";
155	        TEST_CHECK_(strstr(output, expected) == NULL, "Expected output to not contain '%s', got '%s'", expected, output);
156	        /* check extra data was preserved */
157	        expected = "\"extra\":\"Some more data\"";
158	        TEST_CHECK_(strstr(output, expected) != NULL, "Expected output to preserve extra field, got '%s'", output);
159	        free(output);
160	    }
161	
162	    flb_stop(ctx);
163	    flb_destroy(ctx);
164	}
