582	void test_parser_timestamp_timezone(char *tz,
583	                                  char *time_fmt,
584	                                  char *timestamp,
585	                                  char *expected_epoch,
586	                                  int use_system_timezone)
587	{
588	    int ret;
589	    int bytes;
590	    char *output, *original_tz = NULL;
591	    char *saved_tz = NULL;
592	    char p[256];
593	    char expected[256];
594	    flb_ctx_t *ctx;
595	    int in_ffd;
596	    int out_ffd;
597	    int filter_ffd;
598	    struct flb_parser *parser;
