600	
601	    /* Allocate and initialize callback */
602	    cb = flb_malloc(sizeof(struct flb_lib_out_cb));
603	    if (!cb) {
604	        flb_errno();
605	        return;
606	    }
607	    cb->cb = callback_test;
608	    cb->data = NULL;
609	
610	    clear_output();
611	
612	    /* Save current TZ if exists */
613	    original_tz = getenv("TZ");
614	    if (original_tz) {
615	        saved_tz = strdup(original_tz);
616	        if (!saved_tz) {
617	            flb_free(cb);
618	            return;
619	        }
620	    }
621	
622	    /* Set new timezone if provided */
623	    if (tz) {
624	        ret = setenv("TZ", tz, 1);
625	        TEST_CHECK(ret == 0);
626	        tzset(); /* Make sure timezone changes take effect */
627	    }
628	
629	    ctx = flb_create();
630	    TEST_CHECK(ctx != NULL);
631	
632	    /* Configure service */
633	    flb_service_set(ctx,
634	                    "Flush", FLUSH_INTERVAL,
635	                    "Grace", "1",
636	                    "Log_Level", "debug",
637	                    NULL);
638	
639	    /* Input */
640	    in_ffd = flb_input(ctx, (char *) "lib", NULL);
641	    TEST_CHECK(in_ffd >= 0);
642	    flb_input_set(ctx, in_ffd,
643	                  "Tag", "test",
644	                  NULL);
645	
646	    /* Parser */
647	    parser = flb_parser_create("timestamp",
648	                             "regex",
649	                             "^(?<time>.*)$",
650	                             FLB_TRUE,
651	                             time_fmt,
652	                             "time",
653	                             NULL,
654	                             MK_FALSE,
655	                             MK_TRUE,
656	                             use_system_timezone,
657	                             MK_FALSE,
658	                             NULL, 0,
659	                             NULL,
660	                             ctx->config);
661	    TEST_CHECK(parser != NULL);
662	
663	    /* Filter */
664	    filter_ffd = flb_filter(ctx, (char *) "parser", NULL);
665	    TEST_CHECK(filter_ffd >= 0);
666	    ret = flb_filter_set(ctx, filter_ffd,
667	                         "Match", "test",
668	                         "Key_Name", "@timestamp",
669	                         "Parser", "timestamp",
670	                         "Reserve_Data", "On",
671	                         NULL);
672	    TEST_CHECK(ret == 0);
673	
674	    /* Output */
675	    out_ffd = flb_output(ctx, (char *) "lib", cb);
676	    TEST_CHECK(out_ffd >= 0);
677	    flb_output_set(ctx, out_ffd,
678	                   "Match", "*",
679	                   "format", "json",
680	                   NULL);
681	
682	    /* Start the engine */
683	    ret = flb_start(ctx);
684	    TEST_CHECK(ret == 0);
685	
686	    /* Ingest data */
687	    snprintf(p, sizeof(p), "[1448403340, {\"@timestamp\":\"%s\", \"message\":\"This is an example\"}]",
688	             timestamp);
689	    bytes = flb_lib_push(ctx, in_ffd, p, strlen(p));
690	    TEST_CHECK(bytes > 0);
691	
692	    wait_with_timeout(2000, &output);
693	    TEST_CHECK(output != NULL);
694	
695	    if (output != NULL) {
696	        snprintf(expected, sizeof(expected), "[%s", expected_epoch);
697	        TEST_CHECK_(strstr(output, expected) != NULL,
698	                   "Expected output to contain '%s', got '%s'", expected, output);
699	        free(output);
700	    }
701	
702	    flb_stop(ctx);
703	    flb_destroy(ctx);
704	    flb_free(cb);
705	
706	    /* Restore original timezone */
707	    if (saved_tz) {
708	        setenv("TZ", saved_tz, 1);
709	        free(saved_tz);
710	    } else if (original_tz == NULL) {
711	        unsetenv("TZ");
712	    }
713	    tzset();
714	}
