/* Test: time-only format with system timezone near midnight boundary.
 * Verifies that timestamps around midnight get the correct date when
 * time_system_timezone is enabled and no year is present in the format.
 * This reproduces the bug where gmtime_r was used instead of localtime_r
 * for determining the current date.
 */
void test_parser_time_lookup_system_timezone_midnight()
{
    int ret;
    double ns;
    time_t epoch;
    struct flb_tm tm;
    struct flb_parser *p;
    struct flb_config *config;

    config = flb_config_init();

    if (!config) {
        return;
    }

    /* Create a parser with:
     * - time format only has time (no year, no month, no day)
     * - time_system_timezone = true
     * - format like the bug report: %H:%M:%S
     */
    p = flb_parser_create("test_midnight",
                          "regex",
                          "^(?<time>.*)$",
                          FLB_TRUE,
                          "%H:%M:%S",  /* time_fmt - only time, no date */
                          "time",      /* time_key */
                          NULL,        /* no time_offset */
                          MK_FALSE,    /* time_keep */
                          MK_TRUE,     /* time_strict */
                          FLB_TRUE,    /* time_system_timezone */
                          FLB_FALSE,   /* logfmt_no_bare_keys */
                          NULL,        /* types */
                          0,           /* types_len */
                          NULL,        /* decoders */
                          config);
    TEST_CHECK(p != NULL);

    if (p == NULL) {
        flb_config_exit(config);
        return;
    }

    /* Test 1: When we are close to local midnight (e.g., 23:59 local time),
     * a timestamp of 00:01 (just after midnight) should still be on the
     * SAME date, not the previous day.
     *
     * We'll use a known UTC epoch and simulate checking time around midnight.
     * Use a fixed "now" time: March 30, 2026 23:59:00 CEST (UTC+2)
     * This corresponds to UTC: March 30, 2026 21:59:00
     * epoch: let's compute it.
     *
     * March 30, 2026 23:59:00 CEST (UTC+2)
     * = March 30, 2026 21:59:00 UTC
     *
     * We'll use a fixed UTC epoch that, when interpreted in UTC+2,
     * is close to midnight. Then verify that parsing "00:01:00"
     * gives the right date.
     */

    /* Use epoch 1774828740 which is March 30, 2026 21:59:00 UTC
     * In UTC+2 (CEST), that's March 30, 2026 23:59:00
     */
    {
        time_t test_now = 1774828740;  /* March 30, 2026 21:59:00 UTC = 23:59:00 UTC+2 */

        /* Parse "00:01:00" which should be March 31, 2026 00:01:00 local time
         * This is really March 30, 2026 22:01:00 UTC (UTC+2)
         */
        ret = flb_parser_time_lookup("00:01:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);  /* use system timezone */

        /* March 31, 2026 00:01:00 CEST = March 30, 2026 22:01:00 UTC
         * Let's verify the day/month/year is correct in local time */
        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            /* It should be March 31, 2026 (tm_mday=31, tm_mon=2, tm_year=126) */
            TEST_CHECK(check_tm.tm_mday == 31);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March = 2 */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 - 1900 = 126 */
            TEST_CHECK(check_tm.tm_hour == 0);
            TEST_CHECK(check_tm.tm_min == 1);
        }

        TEST_CHECK(ns == 0);
    }

    /* Test 2: Parse "23:59:00" with same "now" time.
     * This should be March 30, 2026 23:59:00 local time (same day as "now")
     */
    {
        time_t test_now = 1774828740;  /* March 30, 2026 21:59:00 UTC = 23:59:00 UTC+2 */

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);  /* use system timezone */

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            /* It should be March 30, 2026 (tm_mday=30, tm_mon=2, tm_year=126) */
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March = 2 */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 - 1900 = 126 */
            TEST_CHECK(check_tm.tm_hour == 23);
            TEST_CHECK(check_tm.tm_min == 59);
        }

        TEST_CHECK(ns == 0);
    }

    /* Test 3: Verify that 00:01:00 epoch > 23:59:00 epoch (monotonically increasing timestamps) */
    {
        time_t test_now = 1774828740;
        time_t epoch_before, epoch_after;

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);
        epoch_before = flb_parser_tm2time(&tm, FLB_TRUE);

        ret = flb_parser_time_lookup("00:01:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);
        epoch_after = flb_parser_tm2time(&tm, FLB_TRUE);

        /* 00:01 should be AFTER 23:59 (i.e., it's the next day) */
        TEST_CHECK(epoch_after > epoch_before);
    }

    flb_parser_destroy(p);
    flb_config_exit(config);
}

TEST_LIST = {
    { "tzone_offset", test_parser_tzone_offset},
    { "time_lookup", test_parser_time_lookup},
    { "json_time_lookup", test_json_parser_time_lookup},
    { "regex_time_lookup", test_regex_parser_time_lookup},
    { "mysql_unquoted" , test_mysql_unquoted },
    { "time_lookup_system_timezone_midnight", test_parser_time_lookup_system_timezone_midnight },
    { 0 }
};

