/* Test: time-only format with system timezone near midnight boundary.
 * Verifies that timestamps around midnight get the correct date when
 * time_system_timezone is enabled and no year is present in the format.
 * This reproduces the bug where gmtime_r was used instead of localtime_r
 * for determining the current date.
 *
 * Scenario from the bug report:
 *   When processing time-only logs around midnight in UTC+2 timezone,
 *   entries at 00:00-02:00 should get the current local date, not
 *   the previous day (which is what gmtime_r would give in UTC).
 */
void test_parser_time_lookup_system_timezone_midnight()
{
    int ret;
    double ns;
    time_t epoch;
    struct flb_tm tm;
    struct flb_parser *p;
    struct flb_config *config;

    config = flb_config_init();

    if (!config) {
        return;
    }

    /* Create a parser with:
     * - time format only has time (no year, no month, no day)
     * - time_system_timezone = true
     * - format like the bug report: %H:%M:%S
     */
    p = flb_parser_create("test_midnight",
                          "regex",
                          "^(?<time>.*)$",
                          FLB_TRUE,
                          "%H:%M:%S",  /* time_fmt - only time, no date */
                          "time",      /* time_key */
                          NULL,        /* no time_offset */
                          MK_FALSE,    /* time_keep */
                          MK_TRUE,     /* time_strict */
                          FLB_TRUE,    /* time_system_timezone */
                          FLB_FALSE,   /* logfmt_no_bare_keys */
                          NULL,        /* types */
                          0,           /* types_len */
                          NULL,        /* decoders */
                          config);
    TEST_CHECK(p != NULL);

    if (p == NULL) {
        flb_config_exit(config);
        return;
    }

    /* Use a fixed "now" time: March 30, 2026 21:59:00 UTC
     * In UTC+2 (CEST), that's March 30, 2026 23:59:00 local time.
     *
     * This simulates being at the end of a day (23:59 local) and
     * processing log entries from earlier in the same day (early morning
     * hours like 00:00-02:00).
     *
     * The key bug: without the fix, gmtime_r gives March 29 date
     * (UTC = 21:59 March 29), so 00:00-02:00 entries get March 29 date.
     * With the fix, localtime_r gives March 30 date, so they get March 30.
     */

    /* Use epoch 1774828740 which is March 30, 2026 21:59:00 UTC
     * In UTC+2 (CEST), that's March 30, 2026 23:59:00 local */
    {
        time_t test_now = 1774828740;

        /* Parse "00:01:00" which should get March 30, 2026 (same local date as "now") */
        ret = flb_parser_time_lookup("00:01:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);  /* use system timezone */

        /* Verify the local date is March 30, 2026, NOT March 29 */
        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March = 2 */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 - 1900 = 126 */
            TEST_CHECK(check_tm.tm_hour == 0);
            TEST_CHECK(check_tm.tm_min == 1);
        }
        TEST_CHECK(ns == 0);
    }

    /* Parse "23:59:00" - should also be on March 30, 2026 */
    {
        time_t test_now = 1774828740;

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);  /* use system timezone */

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March = 2 */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 - 1900 = 126 */
            TEST_CHECK(check_tm.tm_hour == 23);
            TEST_CHECK(check_tm.tm_min == 59);
        }
        TEST_CHECK(ns == 0);
    }

    /* Parse "02:00:00" - should also be on March 30, 2026 */
    {
        time_t test_now = 1774828740;

        ret = flb_parser_time_lookup("02:00:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);  /* use system timezone */

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March = 2 */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 - 1900 = 126 */
            TEST_CHECK(check_tm.tm_hour == 2);
            TEST_CHECK(check_tm.tm_min == 0);
        }
        TEST_CHECK(ns == 0);
    }

    flb_parser_destroy(p);
    flb_config_exit(config);
}

