/* Test: time-only format with system timezone near midnight boundary.
 * Verifies that timestamps around midnight get the correct date when
 * time_system_timezone is enabled and no year is present in the format.
 *
 * This reproduces the bug where gmtime_r was used instead of localtime_r
 * for determining the current date. With gmtime_r, when the system
 * timezone is ahead of UTC (e.g., UTC+2), local midnight is 22:00 UTC
 * on the previous day, so gmtime_r returns the previous day's date.
 * The fix ensures localtime_r is used when time_system_timezone is true.
 */
void test_parser_time_lookup_system_timezone_midnight()
{
    int ret;
    double ns;
    time_t epoch;
    struct flb_tm tm;
    struct flb_parser *p;
    struct flb_config *config;
    char *saved_tz = NULL;
    char *original_tz;

    /* Save and set timezone to a positive offset to reproduce the bug.
     * Using UTC+6 to guarantee the bug manifests:
     * At 01:00 local (UTC+6), UTC is 19:00 previous day.
     * Without the fix, gmtime_r would give previous day's date.
     */
    original_tz = getenv("TZ");
    if (original_tz) {
        saved_tz = strdup(original_tz);
    }

    /* Use a timezone with positive offset so local midnight differs from UTC date */
    setenv("TZ", "XXX-6", 1);
    tzset();

    config = flb_config_init();
    if (!config) {
        goto restore_tz;
    }

    /* Create a parser with:
     * - time format only has time (no year, no month, no day)
     * - time_system_timezone = true
     * - format like the bug report: %H:%M:%S
     */
    p = flb_parser_create("test_midnight",
                          "regex",
                          "^(?<time>.*)$",
                          FLB_TRUE,
                          "%H:%M:%S",  /* time_fmt - only time, no date */
                          "time",      /* time_key */
                          NULL,        /* no time_offset */
                          MK_FALSE,    /* time_keep */
                          MK_TRUE,     /* time_strict */
                          FLB_TRUE,    /* time_system_timezone */
                          FLB_FALSE,   /* logfmt_no_bare_keys */
                          NULL,        /* types */
                          0,           /* types_len */
                          NULL,        /* decoders */
                          config);
    TEST_CHECK(p != NULL);

    if (p == NULL) {
        flb_config_exit(config);
        goto restore_tz;
    }

    /* Use a fixed "now" time: we need an epoch where:
     * - Local time is late in the day (e.g., 23:59)
     * - UTC date is the SAME as local date (so gmtime works for this case)
     * Then we test "00:01" which in the local TZ context should
     * still be on the same day as "now".
     *
     * Actually, the key issue from the bug report is:
     * When processing logs at 00:00-02:00 local time (UTC+2),
     * UTC is 22:00-00:00 (previous day), so gmtime_r gives wrong date.
     *
     * Let's instead use "now" = 01:00 local time (UTC+6 timezone),
     * which is 19:00 UTC the previous day.
     * gmtime_r would give the previous day.
     * localtime_r gives the current day.
     */

    /* Use epoch for March 30, 2026 01:00:00 UTC+6
     * = March 29, 2026 19:00:00 UTC
     */
    {
        /* March 29, 2026 19:00:00 UTC = 1774796400 */
        time_t test_now = 1774796400;

        /* Parse "00:01:00" - this should be March 30, 2026 00:01 UTC+6
         * = March 29, 2026 18:01:00 UTC
         */
        ret = flb_parser_time_lookup("00:01:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);

        /* March 30 00:01 UTC+6 = March 29 18:01 UTC = 1774792860 */
        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 */
            TEST_CHECK(check_tm.tm_hour == 0);
            TEST_CHECK(check_tm.tm_min == 1);
        }
        TEST_CHECK(ns == 0);
    }

    /* Now test: parse "23:59:00" with the same "now" value.
     * This should be March 29, 2026 23:59:00 UTC+6
     * (the previous day from the "now" time which is at 01:00 next day)
     */
    {
        /* Test with "now" = March 29, 2026 19:00:00 UTC (= March 30 01:00 UTC+6) */
        time_t test_now = 1774796400;

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);

        /* Should be March 29, 2026 23:59:00 UTC+6 */
        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            TEST_CHECK(check_tm.tm_mday == 29);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 */
            TEST_CHECK(check_tm.tm_hour == 23);
            TEST_CHECK(check_tm.tm_min == 59);
        }
        TEST_CHECK(ns == 0);
    }

    flb_parser_destroy(p);
    flb_config_exit(config);

restore_tz:
    /* Restore original timezone */
    if (saved_tz) {
        setenv("TZ", saved_tz, 1);
        free(saved_tz);
    } else if (original_tz == NULL) {
        unsetenv("TZ");
    }
    tzset();
}

