            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 = 1900 + 126 */
            TEST_CHECK(check_tm.tm_hour == 0);
            TEST_CHECK(check_tm.tm_min == 1);
        }
        TEST_CHECK(ns == 0);
    }

    /* Test: parse "23:59:00" with same "now" value.
     * Should be March 29, 2026 23:59:00 local */
    {
        time_t test_now = 1774897260;

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            printf("DEBUG test_now=%ld epoch=%ld day=%d mon=%d year=%d hour=%d min=%d\n",
                   (long)test_now, (long)epoch, check_tm.tm_mday, check_tm.tm_mon,
                   check_tm.tm_year, check_tm.tm_hour, check_tm.tm_min);
            TEST_CHECK(check_tm.tm_mday == 29);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 */
            TEST_CHECK(check_tm.tm_hour == 23);
            TEST_CHECK(check_tm.tm_min == 59);
        }
        TEST_CHECK(ns == 0);
    }

    flb_parser_destroy(p);
    flb_config_exit(config);

restore_tz:
    /* Restore original timezone */
    if (saved_tz) {
        setenv("TZ", saved_tz, 1);
        free(saved_tz);
    } else if (original_tz == NULL) {
        unsetenv("TZ");
    }
    tzset();
}

