static char *get_msgpack_map_key(void *buf, size_t buf_size, char *key) {
    int i;
    size_t off = 0;
    int key_size;
    char *ptr = NULL;
    msgpack_unpacked result;
    msgpack_object map;
    msgpack_object k;
    msgpack_object v;

    msgpack_unpacked_init(&result);
    msgpack_unpack_next(&result, buf, buf_size, &off);

    map = result.data;

    if (map.type != MSGPACK_OBJECT_MAP) {
        msgpack_unpacked_destroy(&result);
        return NULL;
    }

    key_size = strlen(key);


    /* printf("map_size: %d\n", map.via.map.size); */

    for (i = 0; i < map.via.map.size; i++) {
        k = map.via.map.ptr[i].key;
        v = map.via.map.ptr[i].val;
        if (k.type != MSGPACK_OBJECT_STR) {
            continue;
        }
        /* printf("key(%.*s)(%d) == (%s)(%d)\n",  k.via.str.size, k.via.str.ptr, k.via.str.size, key, key_size); */
        if (k.via.str.size == key_size && strncmp(key, (char *) k.via.str.ptr,  k.via.str.size) == 0) {
            ptr =  flb_strndup(v.via.str.ptr, v.via.str.size);
            break;
        }
    }

    msgpack_unpacked_destroy(&result);

    return ptr;
}

static int a_mysql_unquote_test(struct flb_parser *p, char *source, char *expected) {

    int ret;
    void *out_buf;
    size_t out_size;
    struct flb_time out_time;
    char *val001;


    ret = flb_parser_regex_do(p, source, strlen(source), &out_buf, &out_size, &out_time);

    TEST_CHECK(ret != -1);
    TEST_CHECK(out_buf != NULL);
    if(ret < 0 || out_buf == NULL) return -1;

    val001 = get_msgpack_map_key(out_buf, out_size, "key001");
    if(!TEST_CHECK(val001 != NULL)) {
        flb_free(out_buf);
        return -1;
    }

    TEST_CHECK_(strcmp(val001,expected) == 0,  "source(%s) expected(%s) got(%s)", source, expected, val001);
    flb_free(val001);
    flb_free(out_buf);

    return 1;
}


void test_mysql_unquoted()
{
    struct flb_parser *p;
    struct flb_config *config;

    config = flb_config_init();

    /* Load parsers */
    load_regex_parsers(config);

    p = flb_parser_get("mysql_quoted_stuff", config);
    TEST_CHECK(p != NULL);

    a_mysql_unquote_test(p,"2010-01-01 02:10:22,plain",    "plain");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,''",       "");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'333'",    "333");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'\\n'",    "\n");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'\\r'",    "\r");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'\\''",    "'");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'\\\"'",   "\"");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'\\\\'",   "\\");
    a_mysql_unquote_test(p,"2010-01-01 02:10:22,'abc\\nE\\\\'",   "abc\nE\\");

    flb_parser_exit(config);
    flb_config_exit(config);


}


/* Test: time-only format with system timezone near midnight boundary.
 * Verifies that timestamps around midnight get the correct date when
 * time_system_timezone is enabled and no year is present in the format.
 *
 * This reproduces the bug where gmtime_r was used instead of localtime_r
 * for determining the current date. The bug manifests when the system
 * timezone is ahead of UTC (e.g., UTC+2 / Europe/Stockholm). At local
 * midnight, UTC is still on the previous day, so gmtime_r returns
 * the previous day's date.
 *
 * The fix ensures localtime_r is used when time_system_timezone is true.
 *
 * Test scenario (matching the bug report):
 *   TZ=UTC+2, now = March 30 00:01 local = March 29 22:01 UTC
 *   Without fix: gmtime_r gives March 29 -> parsed as March 29 00:01 (WRONG)
 *   With fix: localtime_r gives March 30 -> parsed as March 30 00:01 (CORRECT)
 */
void test_parser_time_lookup_system_timezone_midnight()
{
    int ret;
    double ns;
    time_t epoch;
    struct flb_tm tm;
    struct flb_parser *p;
    struct flb_config *config;
    char *saved_tz = NULL;
    char *original_tz;

    /* Save and set timezone to a positive offset to reproduce the bug.
     * Using CET-1 (UTC+1) ensures the bug manifests. POSIX TZ format:
     * CET-1 means local = UTC + 1 hour (ahead of UTC).
     */
    original_tz = getenv("TZ");
    if (original_tz) {
        saved_tz = strdup(original_tz);
    }

    /* CET-1 = UTC+1: local time is 1 hour ahead of UTC */
    setenv("TZ", "CET-1CEST,M3.5.0,M10.5.0/3", 1);
    tzset();

    config = flb_config_init();
    if (!config) {
        goto restore_tz;
    }

    /* Create a parser with:
     * - time format only has time (no year)
     * - time_system_timezone = true
     * - format: %H:%M:%S
     */
    p = flb_parser_create("test_midnight",
                          "regex",
                          "^(?<time>.*)$",
                          FLB_TRUE,
                          "%H:%M:%S",  /* time_fmt - only time, no date */
                          "time",      /* time_key */
                          NULL,        /* no time_offset */
                          MK_FALSE,    /* time_keep */
                          MK_TRUE,     /* time_strict */
                          FLB_TRUE,    /* time_system_timezone */
                          FLB_FALSE,   /* logfmt_no_bare_keys */
                          NULL,        /* types */
                          0,           /* types_len */
                          NULL,        /* decoders */
                          config);
    TEST_CHECK(p != NULL);

    if (p == NULL) {
        flb_config_exit(config);
        goto restore_tz;
    }

    /* Test: "now" = March 30, 2026 00:01:00 CET (UTC+1)
     * This is March 29, 2026 23:01:00 UTC.
     * gmtime_r gives March 29 date.
     * localtime_r gives March 30 date.
     *
     * March 29, 2026 23:01:00 UTC = epoch 1774897260
     */
    {
        time_t test_now = 1774897260;

        /* Parse "00:01:00" - should get March 30 not March 29 */
        ret = flb_parser_time_lookup("00:01:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            printf("DEBUG test_now=%ld epoch=%ld day=%d mon=%d year=%d hour=%d min=%d\n",
                   (long)test_now, (long)epoch, check_tm.tm_mday, check_tm.tm_mon,
                   check_tm.tm_year, check_tm.tm_hour, check_tm.tm_min);
            /* Should be March 30, 2026 00:01:00 local */
            TEST_CHECK(check_tm.tm_mday == 30);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 = 1900 + 126 */
            TEST_CHECK(check_tm.tm_hour == 0);
            TEST_CHECK(check_tm.tm_min == 1);
        }
        TEST_CHECK(ns == 0);
    }

    /* Test: parse "23:59:00" with same "now" value.
     * Should be March 29, 2026 23:59:00 local */
    {
        time_t test_now = 1774897260;

        ret = flb_parser_time_lookup("23:59:00", 8, test_now, p, &tm, &ns);
        TEST_CHECK(ret == 0);

        epoch = flb_parser_tm2time(&tm, FLB_TRUE);

        {
            struct tm check_tm;
            localtime_r(&epoch, &check_tm);
            printf("DEBUG test_now=%ld epoch=%ld day=%d mon=%d year=%d hour=%d min=%d\n",
                   (long)test_now, (long)epoch, check_tm.tm_mday, check_tm.tm_mon,
                   check_tm.tm_year, check_tm.tm_hour, check_tm.tm_min);
            TEST_CHECK(check_tm.tm_mday == 29);
            TEST_CHECK(check_tm.tm_mon == 2);  /* March */
            TEST_CHECK(check_tm.tm_year == 126);  /* 2026 */
            TEST_CHECK(check_tm.tm_hour == 23);
            TEST_CHECK(check_tm.tm_min == 59);
        }
        TEST_CHECK(ns == 0);
    }

    flb_parser_destroy(p);
    flb_config_exit(config);

restore_tz:
    /* Restore original timezone */
    if (saved_tz) {
        setenv("TZ", saved_tz, 1);
        free(saved_tz);
    } else if (original_tz == NULL) {
        unsetenv("TZ");
    }
    tzset();
}

